root.sql:
select sc_mem_m_membership_registered.member_name, sc_mem_m_membership_registered.member_surname, count( sc_mem_m_membership_registered.membership_no) as c_count
from sc_mem_m_ucf_member_group , sc_mem_m_membership_registered where ( sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_mem_m_membership_registered.member_status_code <> '3' ) group by sc_mem_m_membership_registered.member_name, sc_mem_m_membership_registered.member_surname having ( count( sc_mem_m_membership_registered.member_name) > 1 )
/*WHERE*/
